// Package harness contains the shared end-to-end test harness for the Gr4vy Go
// SDK: per-shard merchant isolation, the "endpoint reached" assertion, the
// forward-compatibility response injector, the HTTP-call recorder used for
// endpoint-reach coverage, and small fixtures/helpers. None of this is
// generated by Speakeasy (it lives under test/, scripts/ and a handful of
// unmanaged root files), so an SDK regeneration cannot clobber it.
package harness

import gr4vygo "github.com/gr4vy/gr4vy-go"

// TestMerchant is a merchant-scoped SDK client plus the identifiers a test
// needs. Each CI shard provisions exactly one of these (see GetMerchant), so
// shards share no state and the suite is safe to run in parallel.
type TestMerchant struct {
	// Client is bound to the merchant account via WithMerchantAccountID, so
	// per-call merchant ids can be left nil.
	Client *gr4vygo.Gr4vy
	// MerchantAccountID is the random id this shard's merchant was created with.
	MerchantAccountID string
	// PrivateKey is the PEM signing key, kept so tests can build extra clients
	// (e.g. raw checkout-session field PUTs) without re-reading the environment.
	PrivateKey string
}
